class ParkingSystem {

    private int[] parkingSlots;

    public ParkingSystem(int big, int medium, int small) {
        parkingSlots = new int[] {big, medium, small};
    }

    public boolean addCar(int carType) {
        carType -= 1;
        if (parkingSlots[carType] > 0) {
            parkingSlots[carType] -= 1;
            return true;
        }
        return false;
    }
}

